update public.podcasts set description = 'Get your dose of Bitcoin with weekly news roundups and "Why Are We Bullish" panel shows featuring Bitcoiners from around the world!' where slug = 'btc-sessions' and description like '%FeedSpot%';
update public.podcasts set description = 'The Peter McCormack Show - politics, macro, Bitcoin and AI, long-form interviews. Twice-weekly conversations about money, power, and the shifts reshaping the next decade. Peter McCormack interviews politicians, economists, investors, journalists, founders and Bitcoiners. Past guests include Liz Truss, Lyn Alden, Curtis Yarvin, Matt Goodwin, Mike Green, Balaji Srinivasan, Rupert Lowe, Firas Modad, Scott Horton, Jeff Booth, Connor Leahy, Andrea Miotti, Neema Parvini, Dr Tim Gregory and Simon Dixon. Recurring threads: the debt and inflation endgame, UK political collapse and what comes after, Reform and the populist wave, the Middle East and the American war machine, AI safety and the race for superintelligence, energy and net zero, Bitcoin adoption and policy, and the slow-motion decline of Western institutions. Long-form - most episodes run 60 to 120 minutes. New episodes 2 to 3 times per week. Video on YouTube and Spotify. Host: Peter McCormack, a retired rapper from Bedford, UK, trying to understand this crazy world. Hosted on Acast. See acast.com/privacy for more information.' where slug = 'the-peter-mccormack-show' and description like '%FeedSpot%';
update public.podcasts set description = 'The top stories and best shows in the blockchain world, delivered daily from the team at CoinDesk.' where slug = 'coindesk-podcast-network' and description like '%FeedSpot%';
