update public.podcasts set description = 'It’s your favorite former truck driver, Bitcoin Ben. I’m a cryptocurrency enthusiast. I’m also just an average guy who wants to help bring cryptocurrency into the mainstream. The adoption of cryptocurrency is key to our future. I’m excited to be part of this Revolution. I love my family, wife and three kids. I love you guys, my followers, my fellow cryptocurrency enthusiasts. And don’t forget to kick ass!' where slug = 'bitcoin-ben' and description like '%FeedSpot%';
