update public.podcasts set description = 'Meet The Taco Plebs is a show by the plebs, for the plebs. This is meant to highlight the plebs and give them a bigger audience to have their voices heard. All plebs have an important voice with interesting stories and strong beliefs. The Taco Plebs are the cyber hornets of Bitcoin, calling out scammers & bad actors while stacking sats and helping each other learn as much as they can. You will never meet a more real group of people than the taco plebs. They are all truth and no noise. Sat stacking legends. Hosted by Nik @nikcantmine' where slug = 'meet-the-bitcoin-taco-plebs-bitcoin-magazine' and description like '%FeedSpot%';
update public.podcasts set description = 'Featuring analysis and discourse by hosts Andreas M. Antonopoulos, Dr. Stephanie Murphy, Adam B. Levine, and Jonathan Mohan, episodes feature friendly, in-depth discussions and even-handed interviews. Speaking of Bitcoin (formerly known as Let''s Talk Bitcoin!) is the longest-running English language talk show on the ideas, people and projects surrounding the Bitcoin movement and Cryptocurrency phenomenon.' where slug = 'speaking-of-bitcoin-formerly-let-s-talk-bitcoin' and description like '%FeedSpot%';
update public.podcasts set description = 'Cory Tucek, the CEO of the startup streaming platform Movies Plus, shares his thoughts on the bitcoin world, occasional interviews with Bitcoiners, and talks about the entrepreneur life as well as anything else that crosses his mind. BMS Shows are all hosted by Cory. Occasional Guest Shows: FTM (Fix the Money Fix the World) - Luke Mikic interviews guests, and likes to focus more macro approach. QPOL (Quiet Part Out Loud) - Phil Gibson interviews guests, and likes to get into the geo politics of Bitcoin.' where slug = 'bitcoin-made-simple-podcast' and description like '%FeedSpot%';
