update public.podcasts set description = 'The Bitcoin Source hosted by Dawdu M. Amantanah brings you raw, unfiltered conversations with the pioneers reshaping the Bitcoin landscape. From technocrats and software engineers to entrepreneurs, activists, cypherpunks, media icons, rappers, business leaders, and economists this podcast delves deep, uncovering the diverse voices driving the Bitcoin revolution before the rest of the world takes notice.' where slug = 'the-bitcoin-source-a-bitcoin-conversation' and description like '%FeedSpot%';
update public.podcasts set description = 'A Bitcoin podcast with short episodes (executive summaries) covering my thesis on the future of Bitcoin adoption, competitive landscape, use cases, and network value. I listen to most of the popular bitcoin podcasts and they are 1-2 hours of lost time for most people with any level of bitcoin knowledge. Bitcoin terminal value podcasts are short episodes which revolve around an important topic — packed with information that is being missed (or rarely covered). - Michael Miller IV' where slug = 'bitcoin-terminal-value' and description like '%FeedSpot%';
update public.podcasts set description = 'The Bitcoin In Africa Show is a BTC Only Educational Podcast. During the show we connect with the innovators, founders, ecosystem builders and early adopters that are crafting Africa''s Bitcoin story. The podcast is hosted by former regulator, banker and Bitcoin Activist, Charlene Fadirepo. Enjoy the show where ever you find your podcasts!' where slug = 'bitcoin-in-africa-show' and description like '%FeedSpot%';
